mapper.select:
SELECT d.*, m.nickname AS memberName, m.email AS memberEmail, g.game_date, g.game_time, g.status AS gameStatus, g.score_home AS scoreHome, g.score_away AS scoreAway, IFNULL(s.short_name, s.name) AS stadiumName, t1.name_kr AS homeTeamName, t2.name_kr AS awayTeamName,
-- ⭐️ 승요 판별 정보 (타팀 경기 제외 조건 추가) CASE WHEN d.snapshot_team_code NOT IN (g.home_team_code, g.away_team_code) THEN 'NONE' WHEN g.winning_team = d.snapshot_team_code THEN 'WIN' WHEN g.winning_team = 'DRAW' THEN 'DRAW' WHEN g.winning_team IS NOT NULL THEN 'LOSE' ELSE 'NONE' END AS gameResult
FROM diaries d JOIN members m ON d.member_id = m.member_id LEFT JOIN games g ON d.game_id = g.game_id LEFT JOIN stadiums s ON g.stadium_id = s.stadium_id LEFT JOIN teams t1 ON g.home_team_code = t1.team_code LEFT JOIN teams t2 ON g.away_team_code = t2.team_code WHERE d.diary_id = #{diaryId}
